import pytest
import requests

def test_create_review_unauthenticated_returns_401(api_base_url):
    headers = {"Content-Type": "application/json"}
    payload = {
        "employee_id": "<valid_employee_id>",
        "employee_name": "Jane Doe",
        "review_period": "2024-Q1",
        "rating": 3,
        "reviewer_id": "<valid_reviewer_id>"
    }
    response = requests.post(f"{api_base_url}/api/performance-reviews", json=payload, headers=headers)
    assert response.status_code == 401, f"Expected 401, got {response.status_code}"
